### 파일 1: `src/features/app/word/WordListPage.jsx`

기존 구 word/WordListPage.jsx 패턴을 그대로 재사용하되, Dialog 대신 `navigate('/app/words/:id')`로 변경:

```jsx
import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { CardList } from '@/shared/components/CardList/CardList';
import { SearchForm } from '@/shared/components/SearchForm/SearchForm';
import { Input } from '@/shared/components/ui/input';
import { Label } from '@/shared/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import { Badge } from '@/shared/components/ui/badge';
import { Card } from '@/shared/components/ui/card';
import { emptyToNull } from '@/shared/query/queryHelpers';
import { useListPage } from '@/shared/hooks/useListPage';

const initialFilters = Object.freeze({
    stdWordNm: '',
    stdWordEngAbbrNm: '',
    stdDmnClsfNm: '',
    frmWordYn: '',
    useYn: '',
});

const WordCard = ({ word, onClick }) => (
    <Card
        className='cursor-pointer border-[1.5px] border-border-lt p-4 hover:border-accent transition-colors bg-bg rounded-sm'
        onClick={() => onClick(word)}
    >
        <div className='flex justify-between items-start gap-3'>
            <div className='flex-1 min-w-0'>
                <div className='flex items-baseline flex-wrap gap-2 mb-1'>
                    <span className='font-display italic font-bold text-[18px] text-fg leading-tight'>
                        {word.stdWordNm}
                    </span>
                    {word.stdWordEngAbbrNm && (
                        <span className='font-mono text-[12px] text-muted-foreground'>{word.stdWordEngAbbrNm}</span>
                    )}
                </div>
                <div className='flex flex-wrap gap-4 text-[12px] text-muted-foreground'>
                    {word.stdWordEngNm && <span>{word.stdWordEngNm}</span>}
                    {word.stdDmnClsfNm && <span>도메인 · {word.stdDmnClsfNm}</span>}
                    {word.enctCycl && <span>제정 {word.enctCycl}차</span>}
                </div>
            </div>
            <div className='flex flex-wrap gap-1.5 items-center shrink-0'>
                {word.frmWordYn === 'Y' && <Badge variant='accent'>형식단어</Badge>}
                <Badge variant={word.useYn === 'Y' ? 'success' : 'muted'}>
                    {word.useYn === 'Y' ? '사용' : '미사용'}
                </Badge>
            </div>
        </div>
    </Card>
);

export const WordListPage = () => {
    const [filters, setFilters] = useState(initialFilters);
    const navigate = useNavigate();
    const { request, setRequest, pageQuery } = useListPage({
        listQueryKey: 'word-list',
        listUrl: '/words/search',
        detailQueryKey: 'word-detail',
        detailUrl: '/words',
        initialRequest: { page: 1, size: 20 },
    });

    return (
        <div className='space-y-5'>
            <header className='pb-5 border-b border-border-lt'>
                <h1 className='font-display italic font-bold text-[26px] m-0 mb-1' style={{ letterSpacing: '-0.02em' }}>
                    단어 사전
                </h1>
                <p className='text-[13px] text-muted-foreground m-0'>행정표준용어 기반 단어 데이터</p>
            </header>

            <SearchForm
                onSubmit={() => setRequest({
                    page: 1, size: request.size,
                    stdWordNm: emptyToNull(filters.stdWordNm),
                    stdWordEngAbbrNm: emptyToNull(filters.stdWordEngAbbrNm),
                    stdDmnClsfNm: emptyToNull(filters.stdDmnClsfNm),
                    frmWordYn: emptyToNull(filters.frmWordYn),
                    useYn: emptyToNull(filters.useYn),
                })}
                onReset={() => { setFilters(initialFilters); setRequest({ page: 1, size: request.size }); }}
            >
                <div className='grid w-full gap-3 md:grid-cols-2 xl:grid-cols-5'>
                    <div className='space-y-2'>
                        <Label htmlFor='stdWordNm'>단어명</Label>
                        <Input id='stdWordNm' value={filters.stdWordNm}
                            onChange={(e) => setFilters((c) => ({ ...c, stdWordNm: e.target.value }))} />
                    </div>
                    <div className='space-y-2'>
                        <Label htmlFor='stdWordEngAbbrNm'>영문약어명</Label>
                        <Input id='stdWordEngAbbrNm' value={filters.stdWordEngAbbrNm}
                            onChange={(e) => setFilters((c) => ({ ...c, stdWordEngAbbrNm: e.target.value }))} />
                    </div>
                    <div className='space-y-2'>
                        <Label htmlFor='stdDmnClsfNm'>도메인분류명</Label>
                        <Input id='stdDmnClsfNm' value={filters.stdDmnClsfNm}
                            onChange={(e) => setFilters((c) => ({ ...c, stdDmnClsfNm: e.target.value }))} />
                    </div>
                    <div className='space-y-2'>
                        <Label htmlFor='frmWordYn'>형식단어여부</Label>
                        <Select value={filters.frmWordYn || 'ALL'}
                            onValueChange={(v) => setFilters((c) => ({ ...c, frmWordYn: v === 'ALL' ? '' : v }))}>
                            <SelectTrigger id='frmWordYn' className='bg-background'><SelectValue placeholder='전체' /></SelectTrigger>
                            <SelectContent>
                                <SelectItem value='ALL'>전체</SelectItem>
                                <SelectItem value='Y'>예</SelectItem>
                                <SelectItem value='N'>아니오</SelectItem>
                            </SelectContent>
                        </Select>
                    </div>
                    <div className='space-y-2'>
                        <Label htmlFor='useYn'>사용여부</Label>
                        <Select value={filters.useYn || 'ALL'}
                            onValueChange={(v) => setFilters((c) => ({ ...c, useYn: v === 'ALL' ? '' : v }))}>
                            <SelectTrigger id='useYn' className='bg-background'><SelectValue placeholder='전체' /></SelectTrigger>
                            <SelectContent>
                                <SelectItem value='ALL'>전체</SelectItem>
                                <SelectItem value='Y'>사용</SelectItem>
                                <SelectItem value='N'>미사용</SelectItem>
                            </SelectContent>
                        </Select>
                    </div>
                </div>
            </SearchForm>

            <CardList
                pageData={pageQuery.data ?? null}
                pageSizeOptions={[10, 20, 50, 100]}
                onPageChange={({ page, size }) => setRequest((c) => ({ ...c, page, size }))}
                renderItem={(word) => (
                    <WordCard key={word.id} word={word} onClick={(w) => navigate(`/app/words/${w.id}`)} />
                )}
            />
        </div>
    );
};
