### 파일 2: `src/features/app/word/WordDetailPage.jsx`

```jsx
import { Link, useParams } from 'react-router-dom';
import { useQuery } from '@tanstack/react-query';
import { Card } from '@/shared/components/ui/card';
import { Button } from '@/shared/components/ui/button';
import { Badge } from '@/shared/components/ui/badge';
import { axiosInstance } from '@/shared/api/axiosInstance';

const fetchWord = (id) =>
    axiosInstance.get(`/api/v1/words/${id}`).then((r) => r.data?.data ?? r.data);

export const WordDetailPage = () => {
    const { id } = useParams();
    const { data: word, isLoading, isError } = useQuery({
        queryKey: ['word-detail', id],
        queryFn: () => fetchWord(id),
        enabled: !!id,
    });

    if (isLoading) return <div className='p-6 text-sm text-muted-foreground'>불러오는 중...</div>;
    if (isError || !word) return <div className='p-6 text-sm text-muted-foreground'>용어를 찾을 수 없습니다.</div>;

    return (
        <div className='grid grid-cols-1 xl:grid-cols-[200px_1fr_180px] gap-8 max-w-5xl'>
            {/* 좌: TOC */}
            <aside className='hidden xl:block sticky top-[calc(var(--nav-h,56px)+2rem)] h-fit'>
                <p className='text-[10px] font-bold tracking-[0.1em] uppercase text-muted-foreground mb-3'>목차</p>
                <nav className='space-y-1 text-[13px]'>
                    {['정의', '속성', 'MCP 통합'].map((s) => (
                        <a key={s} href={`#${s}`}
                            className='block text-muted-foreground hover:text-fg no-underline py-1 border-l-2 border-transparent hover:border-accent px-3 transition-all'>
                            {s}
                        </a>
                    ))}
                </nav>
            </aside>

            {/* 중: 본문 */}
            <main className='space-y-8 min-w-0'>
                <div>
                    <Link to='/app/words' className='text-[12px] text-muted-foreground no-underline hover:text-fg'>
                        ← 목록으로
                    </Link>
                    <h1 className='font-display italic font-bold text-[32px] mt-3 mb-1' style={{ letterSpacing: '-0.02em' }}>
                        {word.stdWordNm}
                    </h1>
                    <p className='text-[13px] font-mono text-muted-foreground'>{word.stdWordEngAbbrNm}</p>
                    <div className='flex gap-2 mt-2'>
                        {word.frmWordYn === 'Y' && <Badge variant='accent'>형식단어</Badge>}
                        <Badge variant={word.useYn === 'Y' ? 'success' : 'muted'}>
                            {word.useYn === 'Y' ? '사용' : '미사용'}
                        </Badge>
                    </div>
                </div>

                <section id='정의'>
                    <h2 className='text-[14px] font-bold mb-3 pb-2 border-b border-border-lt'>정의</h2>
                    <p className='text-[14px] text-fg leading-relaxed'>{word.stdWordDf ?? '—'}</p>
                </section>

                <section id='속성'>
                    <h2 className='text-[14px] font-bold mb-3 pb-2 border-b border-border-lt'>속성</h2>
                    <table className='w-full text-[13px] border-collapse'>
                        <tbody>
                            {[
                                ['영문명', word.stdWordEngNm],
                                ['영문 약어', word.stdWordEngAbbrNm],
                                ['도메인 분류', word.stdDmnClsfNm],
                                ['제정 차수', word.enctCycl ? `${word.enctCycl}차` : null],
                                ['사용 여부', word.useYn === 'Y' ? '사용' : '미사용'],
                            ].map(([k, v]) => (
                                <tr key={k} className='border-b border-border-lt'>
                                    <td className='py-2 pr-4 text-muted-foreground w-32 font-medium'>{k}</td>
                                    <td className='py-2 font-mono'>{v ?? '—'}</td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </section>

                <section id='MCP 통합'>
                    <h2 className='text-[14px] font-bold mb-3 pb-2 border-b border-border-lt'>MCP 통합</h2>
                    <pre className='bg-surface border border-border-lt p-4 text-[12px] font-mono overflow-x-auto rounded-sm whitespace-pre-wrap'>
{`// get_term tool
{
  "name": "${word.stdWordNm}",
  "abbr": "${word.stdWordEngAbbrNm ?? ''}",
  "domain": "${word.stdDmnClsfNm ?? ''}"
}`}
                    </pre>
                </section>
            </main>

            {/* 우: 액션 */}
            <aside className='hidden xl:block sticky top-[calc(var(--nav-h,56px)+2rem)] h-fit space-y-2'>
                <p className='text-[10px] font-bold tracking-[0.1em] uppercase text-muted-foreground mb-3'>액션</p>
                <Button variant='outline' size='sm' className='w-full justify-start text-[12px]'>PDF 내보내기</Button>
                <Button variant='outline' size='sm' className='w-full justify-start text-[12px]'>JSON 공유</Button>
                <Link to='/app/forbidden'>
                    <Button variant='outline' size='sm' className='w-full justify-start text-[12px]'>금칙어 검사</Button>
                </Link>
            </aside>
        </div>
    );
};
```

**중요:** `src/shared/api/axiosInstance.js`가 존재하는지 먼저 확인하세요. 없으면 다른 api 파일 경로를 찾아 사용하세요 (Glob으로 `src/shared/api/*.js` 검색).

