                <nav className='space-y-1 text-[13px]'>
                    {['정의', '속성', 'MCP 통합'].map((s) => (
                        <a key={s} href={`#${s}`}
                            className='block text-muted-foreground hover:text-fg no-underline py-1 border-l-2 border-transparent hover:border-accent px-3 transition-all'>
                            {s}
                        </a>
                    ))}
                </nav>
            </aside>

            {/* 중: 본문 */}
            <main className='space-y-8 min-w-0'>
                <div>
                    <Link to='/app/words' className='text-[12px] text-muted-foreground no-underline hover:text-fg'>
                        ← 목록으로
                    </Link>
                    <h1 className='font-display italic font-bold text-[32px] mt-3 mb-1' style={{ letterSpacing: '-0.02em' }}>
                        {word.stdWordNm}
                    </h1>
                    <p className='text-[13px] font-mono text-muted-foreground'>{word.stdWordEngAbbrNm}</p>
                    <div className='flex gap-2 mt-2'>
                        {word.frmWordYn === 'Y' && <Badge variant='accent'>형식단어</Badge>}
                        <Badge variant={word.useYn === 'Y' ? 'success' : 'muted'}>
                            {word.useYn === 'Y' ? '사용' : '미사용'}
                        </Badge>
                    </div>
                </div>

                <section id='정의'>
                    <h2 className='text-[14px] font-bold mb-3 pb-2 border-b border-border-lt'>정의</h2>
                    <p className='text-[14px] text-fg leading-relaxed'>{word.stdWordDf ?? '—'}</p>
                </section>

                <section id='속성'>
                    <h2 className='text-[14px] font-bold mb-3 pb-2 border-b border-border-lt'>속성</h2>
                    <table className='w-full text-[13px] border-collapse'>
                        <tbody>
                            {[
                                ['영문명', word.stdWordEngNm],
                                ['영문 약어', word.stdWordEngAbbrNm],
                                ['도메인 분류', word.stdDmnClsfNm],
                                ['제정 차수', word.enctCycl ? `${word.enctCycl}차` : null],
                                ['사용 여부', word.useYn === 'Y' ? '사용' : '미사용'],
                            ].map(([k, v]) => (
                                <tr key={k} className='border-b border-border-lt'>
                                    <td className='py-2 pr-4 text-muted-foreground w-32 font-medium'>{k}</td>
