                <section id='MCP 통합'>
                    <h2 className='text-[14px] font-bold mb-3 pb-2 border-b border-border-lt'>MCP 통합</h2>
                    <pre className='bg-surface border border-border-lt p-4 text-[12px] font-mono overflow-x-auto rounded-sm whitespace-pre-wrap'>
{`// get_term tool
{
  "name": "${word.stdWordNm}",
  "abbr": "${word.stdWordEngAbbrNm ?? ''}",
  "domain": "${word.stdDmnClsfNm ?? ''}"
}`}
                    </pre>
                </section>
            </main>

            {/* 우: 액션 */}
            <aside className='hidden xl:block sticky top-[calc(var(--nav-h,56px)+2rem)] h-fit space-y-2'>
                <p className='text-[10px] font-bold tracking-[0.1em] uppercase text-muted-foreground mb-3'>액션</p>
                <Button variant='outline' size='sm' className='w-full justify-start text-[12px]'>PDF 내보내기</Button>
                <Button variant='outline' size='sm' className='w-full justify-start text-[12px]'>JSON 공유</Button>
                <Link to='/app/forbidden'>
                    <Button variant='outline' size='sm' className='w-full justify-start text-[12px]'>금칙어 검사</Button>
